import pytest
from src.utils import validate_email, hash_password, verify_password, normalize_email, sanitize_input


def test_validate_email_valid():
    assert validate_email('user@example.com')
    assert validate_email('test.user@domain.org')


def test_validate_email_invalid():
    assert not validate_email('invalid')
    assert not validate_email('@domain.com')
    assert not validate_email('user@')


def test_hash_password():
    hashed = hash_password('secret')
    assert verify_password('secret', hashed)
    assert not verify_password('wrong', hashed)
    # bcrypt outputs differ per call due to unique salts
    assert hash_password('secret') != hash_password('secret')


def test_sanitize_input():
    assert sanitize_input('  hello  ') == 'hello'
    assert sanitize_input('<script>') == '&lt;script&gt;'


def test_normalize_email_strips_whitespace():
    assert normalize_email('  user@example.com  ') == 'user@example.com'


def test_normalize_email_lowercases():
    assert normalize_email('User@Example.COM') == 'user@example.com'


def test_normalize_email_strips_and_lowercases():
    assert normalize_email('  USER@EXAMPLE.COM  ') == 'user@example.com'


def test_normalize_email_already_normal():
    assert normalize_email('user@example.com') == 'user@example.com'

